def normalize(x):
    lo, hi = min(x), max(x)
    if hi == lo:
        return [0.0 for _ in x]
    return [(v - lo) / (hi - lo) for v in x]
# Ví dụ: normalize([2,4,6]) -> [0.0, 0.5, 1.0]

import math
def kmeans_assign(points, centroids):
    labels = []
    for p in points:
        best, bd = 0, float('inf')
        for i, c in enumerate(centroids):
            d = (p[0]-c[0])**2 + (p[1]-c[1])**2
            if d < bd:
                bd, best = d, i
        labels.append(best)
    return labels
# Ví dụ: kmeans_assign([(0,0),(9,9)], [(0,0),(10,10)]) -> [0, 1]
